<span class="line"><span style="color:#61AFEF;">cp</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">../cmake/config.cmake</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">.</span><span style="color:#ABB2BF;"> &amp;&amp; </span><span style="color:#56B6C2;">\\</span></span>
